1→/**
     2→ * @fileoverview Processes Markdown files for consumption by ESLint.
     3→ * @author Brandon Mills
     4→ */
     5→
     6→//-----------------------------------------------------------------------------
     7→// Imports
     8→//-----------------------------------------------------------------------------
     9→
    10→import { fromMarkdown } from "mdast-util-from-markdown";
    11→
    12→//-----------------------------------------------------------------------------
    13→// Type Definitions
    14→//-----------------------------------------------------------------------------
    15→
    16→/** @typedef {import("./types.ts").Block} Block */
    17→/** @typedef {import("./types.ts").RangeMap} RangeMap */
    18→/** @typedef {import("mdast").Node} Node */
    19→/** @typedef {import("mdast").Parent} ParentNode */
    20→/** @typedef {import("mdast").Code} CodeNode */
    21→/** @typedef {import("mdast").Html} HtmlNode */
    22→/** @typedef {import("eslint").Linter.LintMessage} Message */
    23→/** @typedef {import("eslint").Rule.Fix} Fix */
    24→/** @typedef {import("eslint").AST.Range} Range */
    25→
    26→//-----------------------------------------------------------------------------
    27→// Helpers
    28→//-----------------------------------------------------------------------------
    29→
    30→const UNSATISFIABLE_RULES = new Set([
    31→	"eol-last", // The Markdown parser strips trailing newlines in code fences
    32→	"unicode-bom", // Code blocks will begin in the middle of Markdown files
    33→]);
    34→const SUPPORTS_AUTOFIX = true;
    35→
    36→const BOM = "\uFEFF";
    37→
    38→/**
    39→ * @type {Map<string, Block[]>}
    40→ */
    41→const blocksCache = new Map();
    42→
    43→/**
    44→ * Performs a depth-first traversal of the Markdown AST.
    45→ * @param {Node} node A Markdown AST node.
    46→ * @param {{[key: string]: (node?: Node) => void}} callbacks A map of node types to callbacks.
    47→ * @returns {void}
    48→ */
    49→function traverse(node, callbacks) {
    50→	if (callbacks[node.type]) {
    51→		callbacks[node.type](node);
    52→	} else {
    53→		callbacks["*"]();
    54→	}
    55→
    56→	const parent = /** @type {ParentNode} */ (node);
    57→
    58→	if (typeof parent.children !== "undefined") {
    59→		for (let i = 0; i < parent.children.length; i++) {
    60→			traverse(parent.children[i], callbacks);
    61→		}
    62→	}
    63→}
    64→
    65→/**
    66→ * Extracts `eslint-*` or `global` comments from HTML comments if present.
    67→ * @param {string} html The text content of an HTML AST node.
    68→ * @returns {string} The comment's text without the opening and closing tags or
    69→ *     an empty string if the text is not an ESLint HTML comment.
    70→ */
    71→function getComment(html) {
    72→	const commentStart = "<!--";
    73→	const commentEnd = "-->";
    74→	const regex = /^(eslint\b|global\s)/u;
    75→
    76→	if (
    77→		html.slice(0, commentStart.length) !== commentStart ||
    78→		html.slice(-commentEnd.length) !== commentEnd
    79→	) {
    80→		return "";
    81→	}
    82→
    83→	const comment = html.slice(commentStart.length, -commentEnd.length);
    84→
    85→	if (!regex.test(comment.trim())) {
    86→		return "";
    87→	}
    88→
    89→	return comment;
    90→}
    91→
    92→// Before a code block, blockquote characters (`>`) are also considered
    93→// "whitespace".
    94→const leadingWhitespaceRegex = /^[>\s]*/u;
    95→
    96→/**
    97→ * Gets the offset for the first column of the node's first line in the
    98→ * original source text.
    99→ * @param {Node} node A Markdown code block AST node.
   100→ * @returns {number} The offset for the first column of the node's first line.
   101→ */
   102→function getBeginningOfLineOffset(node) {
   103→	return node.position.start.offset - node.position.start.column + 1;
   104→}
   105→
   106→/**
   107→ * Gets the leading text, typically whitespace with possible blockquote chars,
   108→ * used to indent a code block.
   109→ * @param {string} text The text of the file.
   110→ * @param {Node} node A Markdown code block AST node.
   111→ * @returns {string} The text from the start of the first line to the opening
   112→ *     fence of the code block.
   113→ */
   114→function getIndentText(text, node) {
   115→	return leadingWhitespaceRegex.exec(
   116→		text.slice(getBeginningOfLineOffset(node)),
   117→	)[0];
   118→}
   119→
   120→/**
   121→ * When applying fixes, the postprocess step needs to know how to map fix ranges
   122→ * from their location in the linted JS to the original offset in the Markdown.
   123→ * Configuration comments and indentation trimming both complicate this process.
   124→ *
   125→ * Configuration comments appear in the linted JS but not in the Markdown code
   126→ * block. Fixes to configuration comments would cause undefined behavior and
   127→ * should be ignored during postprocessing. Fixes to actual code after
   128→ * configuration comments need to be mapped back to the code block after
   129→ * removing any offset due to configuration comments.
   130→ *
   131→ * Fenced code blocks can be indented by up to three spaces at the opening
   132→ * fence. Inside of a list, for example, this indent can be in addition to the
   133→ * indent already required for list item children. Leading whitespace inside
   134→ * indented code blocks is trimmed up to the level of the opening fence and does
   135→ * not appear in the linted code. Further, lines can have less leading
   136→ * whitespace than the opening fence, so not all lines are guaranteed to have
   137→ * the same column offset as the opening fence.
   138→ *
   139→ * The source code of a non-configuration-comment line in the linted JS is a
   140→ * suffix of the corresponding line in the Markdown code block. There are no
   141→ * differences within the line, so the mapping need only provide the offset
   142→ * delta at the beginning of each line.
   143→ * @param {string} text The text of the file.
   144→ * @param {Node} node A Markdown code block AST node.
   145→ * @param {string[]} comments List of configuration comment strings that will be
   146→ *     inserted at the beginning of the code block.
   147→ * @returns {RangeMap[]} A list of offset-based adjustments, where lookups are
   148→ *     done based on the `js` key, which represents the range in the linted JS,
   149→ *     and the `md` key is the offset delta that, when added to the JS range,
   150→ *     returns the corresponding location in the original Markdown source.
   151→ */
   152→function getBlockRangeMap(text, node, comments) {
   153→	/*
   154→	 * The parser sets the fenced code block's start offset to wherever content
   155→	 * should normally begin (typically the first column of the line, but more
   156→	 * inside a list item, for example). The code block's opening fence may be
   157→	 * further indented by up to three characters. If the code block has
   158→	 * additional indenting, the opening fence's first backtick may be up to
   159→	 * three whitespace characters after the start offset.
   160→	 */
   161→	const startOffset = getBeginningOfLineOffset(node);
   162→
   163→	/*
   164→	 * Extract the Markdown source to determine the leading whitespace for each
   165→	 * line.
   166→	 */
   167→	const code = text.slice(startOffset, node.position.end.offset);
   168→	const lines = code.split("\n");
   169→
   170→	/*
   171→	 * The parser trims leading whitespace from each line of code within the
   172→	 * fenced code block up to the opening fence's first backtick. The first
   173→	 * backtick's column is the AST node's starting column plus any additional
   174→	 * indentation.
   175→	 */
   176→	const baseIndent = getIndentText(text, node).length;
   177→
   178→	/*
   179→	 * Track the length of any inserted configuration comments at the beginning
   180→	 * of the linted JS and start the JS offset lookup keys at this index.
   181→	 */
   182→	const commentLength = comments.reduce(
   183→		(len, comment) => len + comment.length + 1,
   184→		0,
   185→	);
   186→
   187→	/*
   188→	 * In case there are configuration comments, initialize the map so that the
   189→	 * first lookup index is always 0. If there are no configuration comments,
   190→	 * the lookup index will also be 0, and the lookup should always go to the
   191→	 * last range that matches, skipping this initialization entry.
   192→	 */
   193→	const rangeMap = [
   194→		{
   195→			indent: baseIndent,
   196→			js: 0,
   197→			md: 0,
   198→		},
   199→	];
   200→
   201→	// Start the JS offset after any configuration comments.
   202→	let jsOffset = commentLength;
   203→
   204→	/*
   205→	 * Start the Markdown offset at the beginning of the block's first line of
   206→	 * actual code. The first line of the block is always the opening fence, so
   207→	 * the code begins on the second line.
   208→	 */
   209→	let mdOffset = startOffset + lines[0].length + 1;
   210→
   211→	/*
   212→	 * For each line, determine how much leading whitespace was trimmed due to
   213→	 * indentation. Increase the JS lookup offset by the length of the line
   214→	 * post-trimming and the Markdown offset by the total line length.
   215→	 */
   216→	for (let i = 0; i + 1 < lines.length; i++) {
   217→		const line = lines[i + 1];
   218→		const leadingWhitespaceLength =
   219→			leadingWhitespaceRegex.exec(line)[0].length;
   220→
   221→		// The parser trims leading whitespace up to the level of the opening
   222→		// fence, so keep any additional indentation beyond that.
   223→		const trimLength = Math.min(baseIndent, leadingWhitespaceLength);
   224→
   225→		rangeMap.push({
   226→			indent: trimLength,
   227→			js: jsOffset,
   228→
   229→			// Advance `trimLength` character from the beginning of the Markdown
   230→			// line to the beginning of the equivalent JS line, then compute the
   231→			// delta.
   232→			md: mdOffset + trimLength - jsOffset,
   233→		});
   234→
   235→		// Accumulate the current line in the offsets, and don't forget the
   236→		// newline.
   237→		mdOffset += line.length + 1;
   238→		jsOffset += line.length - trimLength + 1;
   239→	}
   240→
   241→	return rangeMap;
   242→}
   243→
   244→const languageToFileExtension = {
   245→	javascript: "js",
   246→	ecmascript: "js",
   247→	typescript: "ts",
   248→	markdown: "md",
   249→};
   250→
   251→/**
   252→ * Extracts lintable code blocks from Markdown text.
   253→ * @param {string} sourceText The text of the file.
   254→ * @param {string} filename The filename of the file
   255→ * @returns {Array<{ filename: string, text: string }>} Source code blocks to lint.
   256→ */
   257→function preprocess(sourceText, filename) {
   258→	const text = sourceText.startsWith(BOM) ? sourceText.slice(1) : sourceText;
   259→	const ast = fromMarkdown(text);
   260→	const blocks = [];
   261→
   262→	blocksCache.set(filename, blocks);
   263→
   264→	/**
   265→	 * During the depth-first traversal, keep track of any sequences of HTML
   266→	 * comment nodes containing `eslint-*` or `global` comments. If a code
   267→	 * block immediately follows such a sequence, insert the comments at the
   268→	 * top of the code block. Any non-ESLint comment or other node type breaks
   269→	 * and empties the sequence.
   270→	 * @type {string[]}
   271→	 */
   272→	let htmlComments = [];
   273→
   274→	traverse(ast, {
   275→		"*"() {
   276→			htmlComments = [];
   277→		},
   278→
   279→		/**
   280→		 * Visit a code node.
   281→		 * @param {CodeNode} node The visited node.
   282→		 * @returns {void}
   283→		 */
   284→		code(node) {
   285→			if (node.lang) {
   286→				const comments = [];
   287→
   288→				for (const comment of htmlComments) {
   289→					if (comment.trim() === "eslint-skip") {
   290→						htmlComments = [];
   291→						return;
   292→					}
   293→
   294→					comments.push(`/*${comment}*/`);
   295→				}
   296→
   297→				htmlComments = [];
   298→
   299→				blocks.push({
   300→					...node,
   301→					baseIndentText: getIndentText(text, node),
   302→					comments,
   303→					rangeMap: getBlockRangeMap(text, node, comments),
   304→				});
   305→			}
   306→		},
   307→
   308→		/**
   309→		 * Visit an HTML node.
   310→		 * @param {HtmlNode} node The visited node.
   311→		 * @returns {void}
   312→		 */
   313→		html(node) {
   314→			const comment = getComment(node.value);
   315→
   316→			if (comment) {
   317→				htmlComments.push(comment);
   318→			} else {
   319→				htmlComments = [];
   320→			}
   321→		},
   322→	});
   323→
   324→	return blocks.map((block, index) => {
   325→		const [language] = block.lang.trim().split(" ");
   326→		const fileExtension = Object.hasOwn(languageToFileExtension, language)
   327→			? languageToFileExtension[language]
   328→			: language;
   329→
   330→		return {
   331→			filename: `${index}.${fileExtension}`,
   332→			text: [...block.comments, block.value, ""].join("\n"),
   333→		};
   334→	});
   335→}
   336→
   337→/**
   338→ * Creates a map function that adjusts messages in a code block.
   339→ * @param {Block} block A code block.
   340→ * @returns {(message: Message) => Message} A function that adjusts messages in a code block.
   341→ */
   342→function adjustBlock(block) {
   343→	const leadingCommentLines = block.comments.reduce(
   344→		(count, comment) => count + comment.split("\n").length,
   345→		0,
   346→	);
   347→
   348→	const blockStart = block.position.start.line;
   349→
   350→	/**
   351→	 * Adjusts ESLint messages to point to the correct location in the Markdown.
   352→	 * @param {Message} message A message from ESLint.
   353→	 * @returns {Message} The same message, but adjusted to the correct location.
   354→	 */
   355→	return function adjustMessage(message) {
   356→		if (!Number.isInteger(message.line)) {
   357→			return {
   358→				...message,
   359→				line: blockStart,
   360→				column: block.position.start.column,
   361→			};
   362→		}
   363→
   364→		const lineInCode = message.line - leadingCommentLines;
   365→
   366→		if (lineInCode < 1 || lineInCode >= block.rangeMap.length) {
   367→			return null;
   368→		}
   369→
   370→		const out = {
   371→			line: lineInCode + blockStart,
   372→			column: message.column + block.rangeMap[lineInCode].indent,
   373→		};
   374→
   375→		if (Number.isInteger(message.endLine)) {
   376→			out.endLine = message.endLine - leadingCommentLines + blockStart;
   377→		}
   378→
   379→		const adjustedFix = {};
   380→
   381→		if (message.fix) {
   382→			adjustedFix.fix = {
   383→				range: /** @type {Range} */ (
   384→					message.fix.range.map(range => {
   385→						// Advance through the block's range map to find the last
   386→						// matching range by finding the first range too far and
   387→						// then going back one.
   388→						let i = 1;
   389→
   390→						while (
   391→							i < block.rangeMap.length &&
   392→							block.rangeMap[i].js <= range
   393→						) {
   394→							i++;
   395→						}
   396→
   397→						// Apply the mapping delta for this range.
   398→						return range + block.rangeMap[i - 1].md;
   399→					})
   400→				),
   401→				text: message.fix.text.replace(
   402→					/\n/gu,
   403→					`\n${block.baseIndentText}`,
   404→				),
   405→			};
   406→		}
   407→
   408→		return { ...message, ...out, ...adjustedFix };
   409→	};
   410→}
   411→
   412→/**
   413→ * Excludes unsatisfiable rules from the list of messages.
   414→ * @param {Message} message A message from the linter.
   415→ * @returns {boolean} True if the message should be included in output.
   416→ */
   417→function excludeUnsatisfiableRules(message) {
   418→	return message && !UNSATISFIABLE_RULES.has(message.ruleId);
   419→}
   420→
   421→/**
   422→ * Transforms generated messages for output.
   423→ * @param {Array<Message[]>} messages An array containing one array of messages
   424→ *     for each code block returned from `preprocess`.
   425→ * @param {string} filename The filename of the file
   426→ * @returns {Message[]} A flattened array of messages with mapped locations.
   427→ */
   428→function postprocess(messages, filename) {
   429→	const blocks = blocksCache.get(filename);
   430→
   431→	blocksCache.delete(filename);
   432→
   433→	return messages.flatMap((group, i) => {
   434→		const adjust = adjustBlock(blocks[i]);
   435→
   436→		return group.map(adjust).filter(excludeUnsatisfiableRules);
   437→	});
   438→}
   439→
   440→export const processor = {
   441→	meta: {
   442→		name: "@eslint/markdown/markdown",
   443→		version: "6.2.1", // x-release-please-version
   444→	},
   445→	preprocess,
   446→	postprocess,
   447→	supportsAutofix: SUPPORTS_AUTOFIX,
   448→};
